import{_ as a,o as e,c as s,S as n}from"./chunks/framework.C6RQlTYc.js";const m=JSON.parse('{"title":"面试官问：什么是大语言模型（LLM）？GPT 系列如何演进？","description":"","frontmatter":{},"headers":[],"relativePath":"面试官问/17ai/q_ai_5-llm.md","filePath":"面试官问/17ai/q_ai_5-llm.md","lastUpdated":1778207238000}'),l={name:"面试官问/17ai/q_ai_5-llm.md"};function r(i,t,d,p,o,c){return e(),s("div",null,[...t[0]||(t[0]=[n(`<h1 id="面试官问-什么是大语言模型-llm-gpt-系列如何演进" tabindex="-1">面试官问：什么是大语言模型（LLM）？GPT 系列如何演进？ <a class="header-anchor" href="#面试官问-什么是大语言模型-llm-gpt-系列如何演进" aria-label="Permalink to &quot;面试官问：什么是大语言模型（LLM）？GPT 系列如何演进？&quot;">​</a></h1><blockquote><p>📚 参考：<a href="/FE-prepare-interview/直击概念/17ai/s_ai_6-llm.html">大语言模型 LLM</a> | <a href="/FE-prepare-interview/直击概念/17ai/s_ai_7-transformer.html">Transformer 架构</a></p></blockquote><p><strong>考察点</strong>：LLM 的核心能力来源（Scaling Law + 涌现能力）、GPT 系列各版本的关键突破、LLM 与本征 AGI 的区别</p><details class="details custom-block"><summary>详细信息</summary><h2 id="核心回答" tabindex="-1">核心回答 <a class="header-anchor" href="#核心回答" aria-label="Permalink to &quot;核心回答&quot;">​</a></h2><p>LLM（Large Language Model）是基于 Transformer 架构、拥有数十亿参数，通过海量文本训练的语言模型。核心能力<strong>来源于规模</strong>：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>Scaling Law（规模定律）：模型参数量越大、训练数据越多、</span></span>
<span class="line"><span>计算量越大 → 模型能力越强，且可预测</span></span>
<span class="line"><span></span></span>
<span class="line"><span>关键发现：当参数量超过某个阈值后 → 涌现能力（Emergence）</span></span>
<span class="line"><span>—— 小模型没有、大模型突然出现的&quot;开悟&quot;能力</span></span>
<span class="line"><span>如：上下文学习、思维链推理、指令遵循</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p><strong>GPT 系列演进</strong>：</p><table><thead><tr><th>版本</th><th style="text-align:center;">年份</th><th>参数量</th><th>关键突破</th></tr></thead><tbody><tr><td>GPT-1</td><td style="text-align:center;">2018</td><td>1.17 亿</td><td>证明预训练+微调可行</td></tr><tr><td>GPT-2</td><td style="text-align:center;">2019</td><td>15 亿</td><td>零样本能力初现</td></tr><tr><td>GPT-3</td><td style="text-align:center;">2020</td><td>1750 亿</td><td>涌现能力，少样本学习</td></tr><tr><td>GPT-3.5</td><td style="text-align:center;">2022</td><td>-</td><td>强化 RLHF 对齐</td></tr><tr><td>GPT-4</td><td style="text-align:center;">2023</td><td>未公开</td><td>多模态（文本+图像），更强推理</td></tr></tbody></table><p><strong>LLM ≠ AGI</strong>：LLM 本质是&quot;next token prediction&quot;，没有真正的理解和意识。但通过 Scaling + RLHF + 工具使用，表现越来越接近通用智能。</p><h2 id="面试回答要点" tabindex="-1">面试回答要点 <a class="header-anchor" href="#面试回答要点" aria-label="Permalink to &quot;面试回答要点&quot;">​</a></h2><ul><li>说清楚&quot;大&quot;的含义：参数量（B 级）和训练数据量</li><li>举例涌现能力：GPT-4 能做小学数学但 GPT-1/2 做不到</li><li>知道 GPT 系列关键演进节点</li></ul></details><blockquote><p>来源：<a href="/FE-prepare-interview/直击概念/17ai/s_ai_6-llm.html">大语言模型 LLM 概念讲解</a></p></blockquote>`,5)])])}const u=a(l,[["render",r]]);export{m as __pageData,u as default};
